<?php
declare(strict_types=1);require_once __DIR__.'/../app/email_marketing.php';proteger_admin();$pdo=getPDO();email_marketing_ensure_schema($pdo);$csrf=email_admin_csrf();$message=$error='';if(isset($_GET['preview'])){header('Content-Type: application/json');$p=email_campaign_preview($pdo,['search'=>$_GET['search']??'','turma'=>$_GET['turma']??'','tag'=>$_GET['tag']??''],15);echo json_encode($p,JSON_UNESCAPED_UNICODE);exit;}if($_SERVER['REQUEST_METHOD']==='POST')try{email_check_csrf();$action=(string)($_POST['action']??'create');if($action==='create'){$id=email_campaign_create($pdo,['name'=>$_POST['name']??'','template_version_id'=>$_POST['template_version_id']??0,'dispatch_type'=>$_POST['dispatch_type']??'instant','scheduled_at'=>$_POST['scheduled_at']??'','filters'=>['search'=>$_POST['search']??'','turma'=>$_POST['turma']??'','tag'=>$_POST['tag']??'']],(string)($_SESSION['equipe_nome']??'Administrador'));header('Location: email_campanhas.php?created='.$id);exit;}$id=(int)($_POST['id']??0);if($action==='pause')$pdo->prepare("UPDATE email_campaigns SET status='paused' WHERE id=:id AND status IN ('queued','scheduled','processing')")->execute(['id'=>$id]);if($action==='resume')$pdo->prepare("UPDATE email_campaigns SET status=IF(scheduled_at>NOW(),'scheduled','queued') WHERE id=:id AND status='paused'")->execute(['id'=>$id]);if($action==='cancel')$pdo->prepare("UPDATE email_campaigns SET status='cancelled',finished_at=NOW() WHERE id=:id")->execute(['id'=>$id]);$message='Campanha atualizada.';}catch(Throwable $e){$error=$e->getMessage();}if(isset($_GET['created']))$message='Campanha criada e audiência congelada.';$templates=$pdo->query("SELECT v.id,CONCAT(t.name,' · v',v.version_number,' · ',v.subject) label FROM email_templates t JOIN email_template_versions v ON v.id=t.current_version_id WHERE t.status='active' ORDER BY t.name")->fetchAll(PDO::FETCH_ASSOC)?:[];$turmas=$pdo->query('SELECT DISTINCT codigo_turma FROM users WHERE codigo_turma IS NOT NULL ORDER BY codigo_turma DESC')->fetchAll(PDO::FETCH_COLUMN)?:[];$tags=$pdo->query('SELECT nome FROM tags WHERE ativo=1 ORDER BY nome')->fetchAll(PDO::FETCH_COLUMN)?:[];$campaigns=$pdo->query("SELECT c.*,(SELECT COUNT(*) FROM email_messages m WHERE m.campaign_id=c.id AND m.delivered_at IS NOT NULL) delivered,(SELECT COUNT(*) FROM email_messages m WHERE m.campaign_id=c.id AND m.first_opened_at IS NOT NULL) opened,(SELECT COUNT(*) FROM email_messages m WHERE m.campaign_id=c.id AND m.first_clicked_at IS NOT NULL) clicked FROM email_campaigns c ORDER BY c.id DESC LIMIT 100")->fetchAll(PDO::FETCH_ASSOC)?:[];$menu='email_marketing';$page_title='Campanhas de e-mail';include __DIR__.'/_header.php';echo email_admin_styles();?><div class="em"><div class="em-head"><div><h1>Campanhas</h1><p class="text-muted">Audiência filtrada, congelada e disparo imediato ou agendado.</p></div></div><?=email_admin_nav('campaigns')?><?php if($message):?><div class="em-msg"><?=email_h($message)?></div><?php endif?><?php if($error):?><div class="em-msg em-error"><?=email_h($error)?></div><?php endif?><div class="em-grid"><section class="em-card"><h2>Nova campanha</h2><form method="post" class="em-form"><input type="hidden" name="csrf" value="<?=email_h($csrf)?>"><input type="hidden" name="action" value="create"><label>Nome interno<input name="name" required></label><label>Modelo<select name="template_version_id" required><option value="">Selecione</option><?php foreach($templates as $t):?><option value="<?=(int)$t['id']?>"><?=email_h($t['label'])?></option><?php endforeach?></select></label><label>Busca por nome/e-mail<input name="search" id="audSearch"></label><label>Turma<select name="turma" id="audTurma"><option value="">Todas</option><?php foreach($turmas as $t):?><option><?=email_h($t)?></option><?php endforeach?></select></label><label>Tag<select name="tag" id="audTag"><option value="">Todas</option><?php foreach($tags as $t):?><option><?=email_h($t)?></option><?php endforeach?></select></label><div id="audPreview" class="em-card">Calculando audiência...</div><label>Disparo<select name="dispatch_type" id="dispatchType"><option value="instant">Imediato</option><option value="scheduled">Agendado</option></select></label><label id="scheduleField" hidden>Data e hora<input type="datetime-local" name="scheduled_at"></label><button class="btn btn-primary" type="submit" <?=$templates?'':'disabled'?>>Criar e colocar na fila</button></form></section><section class="em-card" style="grid-column:span 2"><h2>Histórico</h2><div class="em-table"><table><thead><tr><th>Campanha</th><th>Status</th><th>Elegíveis</th><th>Enviados</th><th>Entregues</th><th>Abertos</th><th>Cliques</th><th></th></tr></thead><tbody><?php foreach($campaigns as $c):?><tr><td><strong><?=email_h($c['name'])?></strong><div class="text-muted"><?=email_h(date('d/m/Y H:i',strtotime($c['created_at'])))?></div></td><td><span class="em-pill"><?=email_h($c['status'])?></span></td><td><?=(int)$c['total_eligible']?></td><td><?=(int)$c['sent_count']?></td><td><?=(int)$c['delivered']?></td><td><?=(int)$c['opened']?></td><td><?=(int)$c['clicked']?></td><td><form method="post" class="em-actions"><input type="hidden" name="csrf" value="<?=email_h($csrf)?>"><input type="hidden" name="id" value="<?=(int)$c['id']?>"><?php if(in_array($c['status'],['queued','scheduled','processing'],true)):?><button class="btn btn-ghost btn-xs" name="action" value="pause">Pausar</button><?php elseif($c['status']==='paused'):?><button class="btn btn-ghost btn-xs" name="action" value="resume">Retomar</button><?php endif?><?php if(!in_array($c['status'],['completed','cancelled'],true)):?><button class="btn btn-danger btn-xs" name="action" value="cancel">Cancelar</button><?php endif?></form></td></tr><?php endforeach?><?php if(!$campaigns):?><tr><td colspan="8" class="text-muted">Nenhuma campanha criada.</td></tr><?php endif?></tbody></table></div></section></div></div><script>(()=>{const t=document.getElementById('dispatchType'),s=document.getElementById('scheduleField');t.onchange=()=>s.hidden=t.value!=='scheduled';let timer;const load=()=>{clearTimeout(timer);timer=setTimeout(async()=>{const q=new URLSearchParams({preview:'1',search:audSearch.value,turma:audTurma.value,tag:audTag.value});const d=await(await fetch('email_campanhas.php?'+q)).json();audPreview.innerHTML='<strong>'+d.eligible+' elegível(is)</strong> de '+d.total+' selecionado(s).'},250)};[audSearch,audTurma,audTag].forEach(e=>e.addEventListener(e.tagName==='INPUT'?'input':'change',load));load()})();</script><?php include __DIR__.'/_footer.php';
